import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

def extract(data):
    result = {}
    for p in data['projects']:
        name = p['path'].split('/')[-1]
        for fw in p['frameworks']:
            for pkg in fw['topLevelPackages']:
                key = (name, fw['framework'], pkg['id'])
                result[key] = pkg['resolvedVersion']
    return result

b = extract(baseline)
a = extract(after)

changes = []
unchanged = []
for key in sorted(set(b.keys()) | set(a.keys())):
    proj, fw, pkg = key
    bv = b.get(key, 'N/A')
    av = a.get(key, 'N/A')
    if bv != av:
        changes.append((proj, fw, pkg, bv, av))
    else:
        unchanged.append((proj, fw, pkg, bv))

print('=== CHANGES ===')
if changes:
    for proj, fw, pkg, bv, av in changes:
        print(f'{proj} ({fw}): {pkg} {bv} -> {av}')
else:
    print('None')

print(f'\n=== UNCHANGED ({len(unchanged)} packages) ===')
for proj, fw, pkg, v in unchanged:
    print(f'{proj} ({fw}): {pkg} {v}')
"

